using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService : IHostedService
{
    private readonly ILogger<ModelTrainingService> _logger;
    private readonly IWebHostEnvironment _env;

    public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _env = env;
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(_env.ContentRootPath, "Data", "tickets.csv");
        var modelPath = Path.Combine(_env.ContentRootPath, "Data", "model.zip");

        _logger.LogInformation("Loading training data from {DataPath}", dataPath);

        var dataView = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        _logger.LogInformation("Evaluating model...");
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation("Model Evaluation Metrics:");
        _logger.LogInformation("  MicroAccuracy:  {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("  MacroAccuracy:  {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  LogLoss:        {LogLoss:F4}", metrics.LogLoss);

        var confusionMatrix = metrics.ConfusionMatrix;
        for (var i = 0; i < confusionMatrix.PerClassPrecision.Count; i++)
        {
            _logger.LogInformation("  Class {Index}: Precision={Precision:F4}, Recall={Recall:F4}",
                i, confusionMatrix.PerClassPrecision[i], confusionMatrix.PerClassRecall[i]);
        }

        mlContext.Model.Save(model, dataView.Schema, modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", modelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;

    public TicketController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<ClassifyTicketResponse> Classify([FromBody] ClassifyTicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        // Get category labels from the model schema
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        _predictionPool.GetModel().GetOutputSchema(SchemaDefinition.Create(typeof(TicketInput)))
            .GetColumnOrNull("Score")?.GetSlotNames(ref labelBuffer);

        var labels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < labels.Length; i++)
        {
            confidence[labels[i]] = prediction.Score[i];
        }

        return Ok(new ClassifyTicketResponse(prediction.Category, confidence));
    }

    [HttpGet("categories")]
    public ActionResult<string[]> GetCategories()
    {
        return Ok(new[] { "Billing", "Technical", "General" });
    }
}

public record ClassifyTicketRequest(string Subject, string Description, int Priority);
public record ClassifyTicketResponse(string Category, Dictionary<string, float> Confidence);

