1. using Microsoft.ML;
2. using TicketClassifier.Models;
3. 
4. namespace TicketClassifier.Services;
5. 
6. public class ModelTrainingService : IHostedService
7. {
8.     private readonly ILogger<ModelTrainingService> _logger;
9.     private readonly IWebHostEnvironment _env;
10. 
11.     public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
12.     {
13.         _logger = logger;
14.         _env = env;
15.     }
16. 
17.     public Task StartAsync(CancellationToken cancellationToken)
18.     {
19.         var mlContext = new MLContext(seed: 42);
20. 
21.         var dataPath = Path.Combine(_env.ContentRootPath, "Data", "tickets.csv");
22.         var modelPath = Path.Combine(_env.ContentRootPath, "Data", "model.zip");
23. 
24.         _logger.LogInformation("Loading training data from {DataPath}", dataPath);
25. 
26.         var dataView = mlContext.Data.LoadFromTextFile<TicketInput>(
27.             dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
28. 
29.         var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);
30. 
31.         var pipeline = mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
32.             .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
33.             .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
34.             .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category)))
35.             .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
36.             .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
37. 
38.         _logger.LogInformation("Training model...");
39.         var model = pipeline.Fit(split.TrainSet);
40. 
41.         _logger.LogInformation("Evaluating model...");
42.         var predictions = model.Transform(split.TestSet);
43.         var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");
44. 
45.         _logger.LogInformation("Model Evaluation Metrics:");
46.         _logger.LogInformation("  MicroAccuracy:  {MicroAccuracy:F4}", metrics.MicroAccuracy);
47.         _logger.LogInformation("  MacroAccuracy:  {MacroAccuracy:F4}", metrics.MacroAccuracy);
48.         _logger.LogInformation("  LogLoss:        {LogLoss:F4}", metrics.LogLoss);
49. 
50.         var confusionMatrix = metrics.ConfusionMatrix;
51.         for (var i = 0; i < confusionMatrix.PerClassPrecision.Count; i++)
52.         {
53.             _logger.LogInformation("  Class {Index}: Precision={Precision:F4}, Recall={Recall:F4}",
54.                 i, confusionMatrix.PerClassPrecision[i], confusionMatrix.PerClassRecall[i]);
55.         }
56. 
57.         mlContext.Model.Save(model, dataView.Schema, modelPath);
58.         _logger.LogInformation("Model saved to {ModelPath}", modelPath);
59. 
60.         return Task.CompletedTask;
61.     }
62. 
63.     public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
64. }
65.

